class Book {
  String title;
  String author;
  int year;

  Book(this.title, this.author, this.year);

  String get description => '$title by $author ($year)';

  bool isOlderThan(int years) {
    return DateTime.now().year - year > years;
  }
}

void main() {
  var book = Book('Dart in Action', 'John Doe', 2022);
  print(book.description);
  print('Older than 3 years: ${book.isOlderThan(3)}');
}
